INSERT INTO `compro_contents` VALUES (1,'welcome','hero','judul','text','Membangun Karakter Bangsa dari Kampus',1,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(2,'welcome','hero','deskripsi','text','Sebuah sistem pemeringkatan nasional yang didedikasikan untuk mengukur, membina, dan mengapresiasi nilai-nilai bela negara di lingkungan pendidikan tinggi.',2,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(3,'welcome','hero','background_image','image','welcome/homepage-bg-1.webp',3,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(4,'welcome','about','judul','text','Patriot Metric',1,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(5,'welcome','about','deskripsi','richtext','<p>Patriot Metric University Ranking merupakan sistem pemeringkatan kinerja yang mengintegrasikan pengukuran capaian akademik, tata kelola institusi,dan pembentukan karakter Bela Negara ke dalam satu kerangka nilai yang utuh, melalui aspek kebijakan, kelembagaan, dan patriotisme peserta didik. </p>\n        <ul><li>Refleksi kinerja institusi berbasis nilai\n</li><li>Penguatan arah kebijakan dan tata kelola\n</li><li>Internalisasi nilai kebangsaan secara terukur\n</li><li>Jejaring dan pembelajaran antar institusi\n</li></ul>',2,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(6,'welcome','about','video_url','url','https://www.youtube.com/embed/nB4YzOhnkBo?si=KXFTn2dRpO-TDdKc',3,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(7,'welcome','institusi','judul','text','Institusi yang Telah Berpartisipasi',1,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(8,'welcome','institusi','deskripsi','text','Bergabung bersama perguruan tinggi terbaik Indonesia dalam mewujudkan kampus berkarakter bela negara.',2,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(9,'welcome','institusi','daftar_baris_1','repeater','[{\"nama\":\"UPN \\\"Veteran\\\" Jawa Timur\",\"logo\":\"welcome\\/institusi-upn-veteran-jatim.webp\"},{\"nama\":\"Universitas Negeri Surabaya\",\"logo\":\"welcome\\/institusi-unesa.webp\"},{\"nama\":\"Universitas 17 Agustus\",\"logo\":\"welcome\\/institusi-untag.webp\"}]',3,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(10,'welcome','institusi','daftar_baris_2','repeater','[{\"nama\":\"UPN \\\"Veteran\\\" Yogyakarta\",\"logo\":\"welcome\\/institusi-upn-yogya.webp\"},{\"nama\":\"Universitas Bhayangkara Jakarta Raya\",\"logo\":\"welcome\\/institusi-ubhara.webp\"},{\"nama\":\"Universitas Mega Buana Palopo\",\"logo\":\"welcome\\/mega-buana-palopo.webp\"}]',4,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(11,'welcome','timeline','judul','text','Timeline Patriot Metric',1,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(12,'welcome','timeline','deskripsi','text','Jadwal dan tahapan proses pemeringkatan institusi Anda.',2,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(13,'welcome','timeline','daftar','repeater','[{\"nomor\":\"01\",\"tanggal\":\"1 - 31 Agustus\",\"judul\":\"Registrasi & Validasi\",\"deskripsi\":\"Periode pendaftaran institusi dan verifikasi data PIC melalui portal Patriot Metric.\"},{\"nomor\":\"02\",\"tanggal\":\"1 Sep - 31 Okt\",\"judul\":\"Pengisian Rubrik\",\"deskripsi\":\"Periode pengisian rubrik penilaian dan unggah bukti pendukung oleh institusi.\"},{\"nomor\":\"03\",\"tanggal\":\"1 - 30 November\",\"judul\":\"Penilaian & Validasi\",\"deskripsi\":\"Tim penilai melakukan verifikasi dan kalkulasi skor pemeringkatan.\"},{\"nomor\":\"04\",\"tanggal\":\"17 Agustus\",\"judul\":\"Penghargaan\",\"deskripsi\":\"Pengumuman hasil dan upacara penghargaan nasional.\"}]',3,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(14,'welcome','instagram','judul','text','Ikuti Aktivitas Kami',1,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(15,'welcome','instagram','deskripsi','text','Pantau perkembangan terbaru Patriot Metric melalui Instagram kami.',2,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(16,'welcome','instagram','posts','repeater','[{\"url\":\"https:\\/\\/www.instagram.com\\/reel\\/DQ5YayFEtfN\\/\",\"gambar\":\"\",\"alt_text\":\"Post Instagram Patriot Metric 1\"},{\"url\":\"https:\\/\\/www.instagram.com\\/p\\/DQssRuxksft\\/\",\"gambar\":\"\",\"alt_text\":\"Post Instagram Patriot Metric 2\"}]',3,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(17,'profile','hero','judul','text','UPN VETERAN JATIM PATRIOT METRIC <br> <span class=\"block mt-1 text-[20px] sm:text-[28px] md:text-[32px] font-semibold text-white/90\">UNIVERSITY RANKING</span>',1,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(18,'profile','hero','deskripsi','text','Sebuah sistem pemeringkatan nasional yang didedikasikan untuk mengukur, membina, dan mengapresiasi nilai-nilai bela negara di lingkungan pendidikan tinggi.',2,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(19,'profile','hero','background_image','image','profile/bg.webp',3,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(20,'profile','latar-belakang','judul','text','Latar Belakang',1,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(21,'profile','latar-belakang','deskripsi','richtext','<p>Di tengah arus globalisasi, nilai patriotisme menghadapi tantangan serius, mulai dari\nmenurunnya pemahaman sejarah, derasnya arus\ndisinformasi dan radikalisme digital yang memicu\npolarisasi, hingga meningkatnya individualisme\nyang menggerus kepedulian sosial.</p><p>\n<strong>Patriot Metric</strong> hadir sebagai jawaban atas\nkebutuhan tersebut. Gagasan ini berangkat dari\nidentitas historis UPN “Veteran” Jawa Timur\nsebagai kampus Bela Negara yang lahir dari\nsemangat para pejuang kemerdekaan, dengan\nsemboyan <i>Widya Mwat Yasa</i> – ilmu pengetahuan\nyang diabdikan untuk pembangunan bangsa.</p>\n<p><strong>Patriot Metric</strong> merupakan instrumen evaluasi yang objektif dan\nterstandarisasi, agar pembinaan kesadaran bela negara, khususnya\ndalam konteks nasionalisme dan patriotisme, dapat dianalisis,\ndievaluasi, dan dikembangkan secara berkelanjutan.</p>\n<p>Instrumen Patriot Metric dirancang berbasis konstruk psikososial\nsehingga tidak hanya dipahami secara normatif, tetapi juga dapat\nmemotivasi institusi pendidikan tinggi melalui internalisasi,\nimplementasi, dan pengembangan nilai-nilai bela negara serta\nkarakter kebangsaan dalam Tridharma Perguruan Tinggi.</p>\n',2,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(22,'profile','tujuan-utama','judul','text','Tujuan Pemeringkatan',1,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(23,'profile','tujuan-utama','deskripsi','text',' ',2,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(24,'profile','tujuan-utama','daftar','repeater','[{\"nomor\":\"01\",\"judul\":\"Menjadi Instrumen\\nEvaluasi Pembinaan\\nKesadaran Bela Negara\",\"deskripsi\":\"Menilai sejauh mana upaya\\npembinaan karakter bela negara\\ntelah diinternalisasikan melalui\\nkebijakan dan program\\nperguruan tinggi.\"},{\"nomor\":\"02\",\"judul\":\"Memperkuat Ekosistem\\nPerguruan Tinggi Berbasis\\nNilai-nilai Bela Negara\",\"deskripsi\":\"Tercipta ekosistem perguruan\\ntinggi yang lebih kuat dalam\\nmenanamkan nilai-nilai bela\\nnegara dan tanggung jawab\\nsosial melalui berbagai aspek\\nTridharma Perguruan Tinggi.\"},{\"nomor\":\"03\",\"judul\":\"Mendorong Sinergi\\nAntar-Perguruan Tinggi\",\"deskripsi\":\"Perguruan Tinggi dapat saling\\nmemotivasi, bersama-sama\\nmembangun generasi muda\\nyang berdaya saing global,\\nadaptif, dan patriotik.\"}]',3,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(25,'profile','manfaat-pemeringkatan','judul','text','Manfaat Pemeringkatan',1,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(26,'profile','manfaat-pemeringkatan','daftar','repeater','[{\"nomor\":\"01\",\"judul\":\"Meningkatkan Kesadaran Bela Negara\",\"deskripsi\":\"Mendorong Perguruan Tinggi untuk mewujudkan dan meningkatkan karakter bela negara.\"},{\"nomor\":\"02\",\"judul\":\"Membangun Jejaring dan Kolaborasi Nasional\",\"deskripsi\":\"Membuka peluang bagi perguruan tinggi peserta menjadi bagian dari jejaring Patriot Metric yang memungkinkan kolaborasi di tingkat nasional.\"},{\"nomor\":\"03\",\"judul\":\"Mendapatkan Pengakuan dan Reputasi\",\"deskripsi\":\"Meningkatkan citra dan reputasi perguruan tinggi sebagai kampus yang berkomitmen pada penguatan karakter bela negara.\"},{\"nomor\":\"04\",\"judul\":\"Mendorong Perubahan dan Aksi Sosial\",\"deskripsi\":\"Perguruan tinggi dapat melakukan perubahan karakter dalam segala aspek Tridharma Perguruan Tinggi.\"}]',2,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(27,'tim','hero','judul','text','Tim Kami',1,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(28,'tim','hero','deskripsi','text','Para profesional yang berdedikasi dalam mengembangkan dan mengelola sistem pemeringkatan Patriot Metric.',2,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(29,'tim','team-grid','daftar','repeater','[{\"nama\":\"Lorem Ipsum\",\"role\":\"Lorem Ipsum\",\"foto\":\"tim\\/blank-profile.webp\"},{\"nama\":\"Lorem Ipsum\",\"role\":\"Lorem Ipsum\",\"foto\":\"tim\\/blank-profile.webp\"},{\"nama\":\"Lorem Ipsum\",\"role\":\"Lorem Ipsum\",\"foto\":\"tim\\/blank-profile.webp\"},{\"nama\":\"Lorem Ipsum\",\"role\":\"Lorem Ipsum\",\"foto\":\"tim\\/blank-profile.webp\"}]',1,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(30,'penghargaan','hero','judul','text','Galeri Penghargaan',1,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(31,'penghargaan','hero','deskripsi','text','Penghormatan tertinggi bagi institusi yang telah membuktikan dedikasinya dalam membangun karakter patriotik dan bela negara.',2,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(32,'penghargaan','hero','background_image','image','penghargaan/hero-bg.webp',3,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(33,'penghargaan','daftar-penerima','judul','text','Daftar Institusi Peraih Penghargaan',1,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(34,'penghargaan','daftar-penerima','daftar','repeater','[{\"nama\":\"Lorem Ipsum\",\"logo\":\"welcome\\/logo-upn.webp\",\"rating\":5},{\"nama\":\"Lorem Ipsum\",\"logo\":\"welcome\\/logo-upn.webp\",\"rating\":5},{\"nama\":\"Lorem Ipsum\",\"logo\":\"welcome\\/logo-upn.webp\",\"rating\":4.5},{\"nama\":\"Lorem Ipsum\",\"logo\":\"welcome\\/logo-upn.webp\",\"rating\":4},{\"nama\":\"Lorem Ipsum\",\"logo\":\"welcome\\/logo-upn.webp\",\"rating\":5},{\"nama\":\"Lorem Ipsum\",\"logo\":\"welcome\\/logo-upn.webp\",\"rating\":4}]',2,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(35,'panduan','hero','judul','text','Panduan Penggunaan Sistem',1,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(36,'panduan','hero','deskripsi','text','Langkah mudah dan terstruktur untuk mendaftarkan dan menilai institusi Anda di Patriot Metric.',2,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(37,'panduan','hero','tombol_teks','text','Pedoman Patriot Metric UPN Veteran Jatim',3,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(38,'panduan','hero','tombol_link','url','https://bit.ly/PEDOMANPATRIOTMETRIC',4,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(39,'panduan','steps','daftar','repeater','[{\"label\":\"Langkah 1\",\"judul\":\"Input Data\",\"deskripsi\":\"Peserta mengisi formulir pemeringkatan secara daring dan mengunggah dokumen pendukung.\",\"icon\":\"user-plus\"},{\"label\":\"Langkah 2\",\"judul\":\"Validasi\",\"deskripsi\":\"Proses validasi oleh Tim Evaluator untuk memastikan keabsahan data, termasuk wawancara & visitasi lapangan.\",\"icon\":\"file-check\"},{\"label\":\"Langkah 3\",\"judul\":\"Penilaian\",\"deskripsi\":\"Penilaian untuk setiap indikator berbentuk skor angka dan diolah secara statistik.\",\"icon\":\"trending-up\"},{\"label\":\"Langkah 4\",\"judul\":\"Pengumuman\",\"deskripsi\":\"Hasil akhir ditetapkan berdasarkan skor kumulatif dan disampaikan dalam bentuk peringkat bintang.\",\"icon\":\"check-circle\"}]',1,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(40,'panduan','faq','judul','text','Tanya Jawab (FAQ)',1,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(41,'panduan','faq','daftar','repeater','[{\"pertanyaan\":\"Siapa yang berhak mendaftarkan institusi?\",\"jawaban\":\"Pendaftaran dapat dilakukan oleh perwakilan resmi (PIC) yang ditunjuk oleh rektorat atau pimpinan perguruan tinggi dengan melampirkan Surat Tugas resmi.\"},{\"pertanyaan\":\"Berapa lama proses validasi berlangsung?\",\"jawaban\":\"Proses validasi berlangsung selama 15 hari kerja setelah pendaftaran diterima dan dokumen dinyatakan lengkap.\"},{\"pertanyaan\":\"Apakah sistem ini berbayar?\",\"jawaban\":\"Tidak, sistem Patriot Metric sepenuhnya gratis dan terbuka untuk seluruh perguruan tinggi di Indonesia.\"}]',2,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(42,'pengumuman','hero','judul','text','Pengumuman',1,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(43,'pengumuman','hero','deskripsi','text','Dokumen resmi dan surat edaran Patriot Metric.',2,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(44,'pengumuman','artikel','daftar','repeater','[{\"tanggal\":\"2025-07-01\",\"judul\":\"Surat Edaran Pendaftaran Patriot Metric 2025\",\"excerpt\":\"Surat edaran resmi untuk seluruh perguruan tinggi\",\"dokumen\":\"\"},{\"tanggal\":\"2025-08-15\",\"judul\":\"Panduan Pengisian Rubrik Penilaian Bela Negara\",\"excerpt\":\"Petunjuk teknis pengisian rubrik\",\"dokumen\":\"\"},{\"tanggal\":\"2025-09-01\",\"judul\":\"SK Penetapan Tim Reviewer Patriot Metric 2025\",\"excerpt\":\"Surat keputusan penetapan tim penilai\",\"dokumen\":\"\"},{\"tanggal\":\"2025-10-01\",\"judul\":\"Jadwal Pelaksanaan Penilaian Periode 2025-2026\",\"excerpt\":\"Timeline resmi kegiatan penilaian\",\"dokumen\":\"\"},{\"tanggal\":\"2025-11-15\",\"judul\":\"Surat Edaran Perpanjangan Batas Waktu Pengumpulan Data\",\"excerpt\":\"Perpanjangan deadline pengumpulan dokumen\",\"dokumen\":\"\"},{\"tanggal\":\"2026-01-10\",\"judul\":\"Pengumuman Hasil Pemeringkatan Patriot Metric 2025\",\"excerpt\":\"Hasil resmi pemeringkatan nasional\",\"dokumen\":\"\"}]',1,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(45,'berita','hero','judul','text','Berita',1,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(46,'berita','hero','deskripsi','text','Informasi dan berita terbaru seputar kegiatan Patriot Metric dan perguruan tinggi.',2,'2026-06-02 06:53:11','2026-06-02 06:53:11'),(47,'berita','berita','daftar','repeater','[{\"tanggal\":\"2025-01-27\",\"judul\":\"Mendiktisaintek Resmikan Menara Wimaya UPN \\\"Veteran\\\" Jawa Timur\",\"excerpt\":\"Menteri Pendidikan Tinggi, Sains, dan Teknologi Brian Yuliarto menekankan pentingnya pemanfaatan bersama sumber daya pendidikan tinggi saat meresmikan Menara Wimaya.\",\"konten\":\"Menteri Pendidikan Tinggi, Sains, dan Teknologi (Mendiktisaintek) Brian Yuliarto menekankan pentingnya pemanfaatan bersama sumber daya pendidikan tinggi, khususnya laboratorium dan peralatan riset, agar utilisasinya semakin optimal. Hal tersebut disampaikan saat meresmikan Menara Wimaya (Twin Tower) Universitas Pembangunan Nasional (UPN) \\\"Veteran\\\" Jawa Timur, Senin (27\\/1).\\n\\nMendiktisaintek mendorong penguatan kolaborasi antarkampus, baik perguruan tinggi negeri maupun swasta. Menurutnya, praktik berbagi fasilitas dan sumber daya telah menjadi hal yang lazim di berbagai negara dan perlu terus diperkuat di Indonesia. \\\"Gedungnya memang ada di sini, tetapi fasilitas dan laboratoriumnya tentu bisa dimanfaatkan juga oleh kampus-kampus lain. Riset dan pengajaran bisa kita lakukan bersama-sama,\\\" ujar Menteri Brian.\\n\\nPeresmian Menara Wimaya merupakan bagian dari kunjungan kerja Mendiktisaintek ke UPN \\\"Veteran\\\" Jawa Timur sekaligus bentuk apresiasi atas komitmen kampus dalam membangun fasilitas pendidikan tinggi secara mandiri dan berkelanjutan. Ia menilai pembangunan gedung tersebut sebagai capaian penting yang mencerminkan semangat kolegialitas dan kebersamaan antarkampus.\\n\\nSelain infrastruktur, Mendiktisaintek juga mendorong pengembangan bahan ajar daring berbasis video yang dapat diakses secara luas sebagai implementasi praktik perguruan tinggi kelas dunia. \\\"Dosen-dosen terbaik bisa membagikan ilmunya ke seluas-luasnya masyarakat, dan kampus-kampus di berbagai daerah dapat memanfaatkannya,\\\" katanya.\\n\\nDalam kesempatan yang sama, Menteri Brian menegaskan bahwa keunggulan perguruan tinggi tidak hanya ditentukan oleh kemegahan infrastruktur, tetapi juga oleh lingkungan kampus yang tertata, bersih, dan memberikan layanan prima. Lingkungan tersebut dinilai penting dalam membentuk karakter, etos kerja, dan integritas mahasiswa sebagai calon sumber daya manusia unggul.\\n\\nRektor UPN \\\"Veteran\\\" Jawa Timur, Prof. Dr. Ir. Akhmad Fauzi, MMT.,IPU menyampaikan bahwa pembangunan Menara Wimaya merupakan bagian dari transformasi berkelanjutan kampus bela negara dalam memperkuat atmosfer akademik.\\n\\nMenara Wimaya dibangun secara multi-years selama tiga tahun oleh PT PP, dengan peletakan batu pertama pada 16 Juli 2022 dan rampung pada 2025. Gedung kembar seluas sekitar 29.000 meter persegi dan terdiri atas 13 lantai ini didanai melalui Penerimaan Negara Bukan Pajak (PNBP), serta dirancang sebagai simbol konektivitas dan kolaborasi antarbidang keilmuan melalui sky bridge yang menghubungkan kedua menara.\\n\\nSelain peresmian Menara Wimaya, UPN \\\"Veteran\\\" Jawa Timur juga meluncurkan dua program strategis, yakni Patriot Metric University Ranking dan U-Bridge Program. Kedua program tersebut diposisikan sebagai penguat transformasi institusi, sejalan dengan pembangunan infrastruktur utama kampus dalam mendukung kebijakan Diktisaintek Berdampak dan upaya mencetak lulusan berkarakter, berdaya saing, serta berkontribusi nyata bagi bangsa.\",\"gambar\":\"\"},{\"tanggal\":\"2025-01-27\",\"judul\":\"Manfaat Pemeringkatan Patriot Metric bagi Perguruan Tinggi\",\"excerpt\":\"Patriot Metric memberikan berbagai manfaat strategis bagi perguruan tinggi yang berpartisipasi dalam pemeringkatan.\",\"konten\":\"Meningkatkan Kesadaran Bela Negara; Mendorong Perguruan Tinggi untuk mewujudkan dan meningkatkan karakter bela negara.\\n\\nMembangun Jejaring dan Kolaborasi Nasional; Membuka peluang bagi perguruan tinggi peserta menjadi bagian dari jejaring Patriot Metric yang memungkinkan kolaborasi di tingkat nasional.\\n\\nMendapatkan Pengakuan dan Reputasi; Meningkatkan citra dan reputasi perguruan tinggi sebagai kampus yang berkomitmen pada penguatan karakter bela negara.\\n\\nMendorong Perubahan dan Aksi Sosial; Perguruan tinggi dapat melakukan perubahan karakter dalam segala aspek Tridharma Perguruan Tinggi.\",\"gambar\":\"\"}]',1,'2026-06-02 06:53:11','2026-06-02 06:53:11');
